class Solution:
    def minCost(self, s, cost):
        # Independent construction: accumulate per-letter totals in a dict keyed
        # by character (rather than a 26-slot array indexed by ord()), then take
        # the minimum deletion total directly instead of via a total-minus-max shortcut.
        totals = {}
        for ch, c in zip(s, cost):
            totals[ch] = totals.get(ch, 0) + c
        grand_total = sum(cost)
        best = None
        for ch, keep in totals.items():
            delete_cost = grand_total - keep
            if best is None or delete_cost < best:
                best = delete_cost
        return best

