var minCost = function(s, cost) {
    const totals = new Array(26).fill(0);
    for (let i = 0; i < s.length; i++) {
        totals[s.charCodeAt(i) - 97] += cost[i];
    }
    const grandTotal = cost.reduce((a, b) => a + b, 0);
    return grandTotal - Math.max(...totals);
};
